  { q: "Which GDS Branch Postmaster was specially recognized for opening 558 Sukanya Samriddhi Accounts and 1,830 POSB accounts?", options: ["Smt. Geeta Devi", "Mrs. Anjana Uikey", "Ms. Rekha Sharma", "Smt. Vandita Kaul"], answer: 1, explanation: "Mrs. Anjana Uikey, a GDS Branch Postmaster, was specially recognized for opening 558 Sukanya Samriddhi Accounts and 1,830 POSB accounts." },
  { q: "For what purpose was the 'Dak Karmayogi' portal launched?", options: ["Online stamp purchase", "Customer grievance redressal", "Capacity building and training of employees", "Tracking international parcels"], answer: 2, explanation: "The 'Dak Karmayogi' portal was launched for capacity building and training of Department of Posts employees." },
  { q: "During the National Postal Week 2025, which specific day was observed on 9th October?", options: ["Technology Day", "Financial Inclusion Day", "World Post Day", "Customer Day"], answer: 2, explanation: "World Post Day was observed on 9th October during National Postal Week 2025." },
  { q: "Under the Mission Karmayogi initiative, what is the name of the training program launched by the Capacity Building Commission?", options: ["Dak Seva Bhav", "Serving the Karmayogi Way (Seva Bhav)", "Mission Excellence", "Dak Pragati"], answer: 1, explanation: "'Serving the Karmayogi Way (Seva Bhav)' is the training program launched under the Mission Karmayogi initiative by the Capacity Building Commission." },
  { q: "India Post collaborated with which telecom operator for the sale and recharge of SIM cards?", options: ["Jio", "Airtel", "BSNL", "Vi"], answer: 2, explanation: "India Post collaborated with BSNL for the sale and recharge of SIM cards." },
  { q: "Under which theme did India Post celebrate the 11th International Day of Yoga?", options: ["Yoga for Harmony", "Yoga for Humanity", "Yoga for One Earth, One Health", "Yoga for Peace"], answer: 2, explanation: "India Post celebrated the 11th International Day of Yoga under the theme 'Yoga for One Earth, One Health'." },
  { q: "Which campaign was organized at the National Philatelic Museum to mark the 75th anniversary of India's Constitution?", options: ["My Country My Pride", "Hamara Samvidhan Hamara Swabhiman", "Constitution 75", "Har Ghar Tiranga"], answer: 1, explanation: "The 'Hamara Samvidhan Hamara Swabhiman' campaign was organized at the National Philatelic Museum to mark the 75th anniversary of India's Constitution." },
  { q: "India Post Payments Bank (IPPB) was launched on which date?", options: ["1st September 2018", "15th August 2019", "1st January 2020", "31st December 2021"], answer: 0, explanation: "India Post Payments Bank (IPPB) was launched on 1st September 2018." },
  { q: "The e-Payment service in Post Offices is primarily used for which purpose?", options: ["Sending parcels", "Buying stamps", "Collection of bills and other payments", "Depositing into savings account"], answer: 2, explanation: "The e-Payment service in Post Offices is primarily used for collection of bills and other payments." },
  { q: "Which life insurance product offered by IPPB is a pure life term insurance plan?", options: ["Guaranteed Pension Goal", "Smart Protect Goal", "Group Accident Guard", "Postal Life Insurance"], answer: 1, explanation: "'Smart Protect Goal', offered by IPPB, is a pure life term insurance plan." },
  { q: "What is the service charge for issuing a statement of account at a Post Office?", options: ["Rs. 50", "Rs. 10 (per registration)", "Rs. 20 (per case)", "No fee is charged"], answer: 2, explanation: "The service charge for issuing a statement of account is Rs. 20 per case." },
  { q: "Is there a fee for changing or canceling a nomination in a Post Office savings account?", options: ["Yes, Rs. 100", "Yes, Rs. 50", "Yes, Rs. 10", "No, there is no fee applicable"], answer: 3, explanation: "There is no fee applicable for changing or canceling a nomination in a Post Office savings account." },
  { q: "What is the cost associated with pledging a Post Office savings account?", options: ["Rs. 50", "Rs. 100", "Rs. 20", "There is no charge for pledging"], answer: 1, explanation: "Pledging a Post Office savings account costs Rs. 100." },
  { q: "How are charges applied for issuing a cheque book for a Post Office Savings Bank Account?", options: ["A flat fee of Rs. 100 is charged", "The first 10 leaves per year are free, then Rs. 2 per leaf", "Rs. 2 is charged for every cheque leaf issued", "Cheque books are provided free of charge"], answer: 1, explanation: "The first 10 cheque leaves per year are free, and thereafter Rs. 2 is charged per leaf." },
  { q: "What is the fee for getting a new passbook if the original is lost or mutilated?", options: ["Rs. 50", "Rs. 20", "Rs. 10 (per registration)", "Rs. 100"], answer: 2, explanation: "The fee for getting a new passbook if the original is lost or mutilated is Rs. 10 per registration." },
  { q: "What is required to be submitted for the transfer of a Post Office account?", options: ["Only the prescribed application form", "Passbook, application form, and a fee of Rs. 100 + GST", "Just the passbook and a fee of Rs. 100", "No documents are needed, only a verbal request"], answer: 1, explanation: "For transfer of a Post Office account, the passbook, application form, and a fee of Rs. 100 + GST must be submitted." },
  { q: "Which of the following account types can be transferred between a Bank and a Post Office?", options: ["Only Post Office Savings Accounts", "All time deposit accounts", "PPF, SSA, and SCSS accounts", "National Savings Certificate"], answer: 2, explanation: "PPF, SSA, and SCSS accounts can be transferred between a Bank and a Post Office." },
  { q: "Where can a Post Office savings account be transferred?", options: ["Only to a main branch Post Office", "From any CBS Post Office to another CBS Post Office", "It cannot be transferred once opened", "Only to a bank branch"], answer: 1, explanation: "A Post Office savings account can be transferred from any CBS Post Office to another CBS Post Office." },
  { q: "Which two schemes offer the highest interest rate of 8.2%?", options: ["Senior Citizen Savings Scheme and Public Provident Fund Scheme", "Sukanya Samriddhi Account Scheme and Senior Citizen Savings Scheme", "National Savings Certificate and Sukanya Samriddhi Account Scheme", "5 Year Time Deposit and Kisan Vikas Patra"], answer: 1, explanation: "The Sukanya Samriddhi Account Scheme and Senior Citizen Savings Scheme offer the highest interest rate of 8.2%." },
  { q: "What is the compounding frequency for a 5 Year Recurring Deposit Scheme?", options: ["Annually", "Monthly and paid", "Quarterly", "Annually and paid"], answer: 2, explanation: "The 5 Year Recurring Deposit Scheme has a quarterly compounding frequency." },
  { q: "According to the interest rate table, what is the interest rate on a 2 Year Time Deposit?", options: ["6.9%", "7.0%", "7.1%", "7.5%"], answer: 1, explanation: "The interest rate on a 2 Year Time Deposit is 7.0%." },
  { q: "Which of the following schemes has its interest compounded annually?", options: ["5 Year Time Deposit", "Monthly Income Account", "Mahila Samman Savings Certificate", "Public Provident Fund Scheme"], answer: 3, explanation: "The Public Provident Fund Scheme has its interest compounded annually." },
  { q: "What is the specified maturity period for the Kisan Vikas Patra?", options: ["10 years", "120 months", "115 months", "5 years"], answer: 2, explanation: "The specified maturity period for the Kisan Vikas Patra is 115 months." },
  { q: "What is the interest rate for the Mahila Samman Savings Certificate?", options: ["8.2%", "7.7%", "7.5%", "7.1%"], answer: 2, explanation: "The Mahila Samman Savings Certificate offers an interest rate of 7.5%." },
  { q: "Which scheme provides interest that is 'Quarterly and Paid'?", options: ["2 Year Time Deposit", "5 Year Recurring Deposit Scheme", "Senior Citizen Savings Scheme", "Monthly Income Account"], answer: 2, explanation: "The Senior Citizen Savings Scheme provides interest that is 'Quarterly and Paid'." },
  { q: "Which of these schemes offers the lowest interest rate?", options: ["Post Office Savings Account", "1 Year Time Deposit", "5 Year Recurring Deposit Scheme", "Public Provident Fund Scheme"], answer: 0, explanation: "The Post Office Savings Account offers the lowest interest rate, at 4.0%." },
  { q: "What is the compounding frequency for the National Savings Certificate (VIII Issue)?", options: ["Annually", "Quarterly", "Monthly", "Monthly and paid"], answer: 0, explanation: "The National Savings Certificate (VIII Issue) has an annual compounding frequency." },
  { q: "Through which online portals can customers order Gangajal from India Post?", options: ["Only E-Commerce Portal", "Both e-Commerce Portal and e-Postoffice Portal", "Only at Post Office Counters", "Only through the mobile app"], answer: 1, explanation: "Customers can order Gangajal from India Post through both the e-Commerce Portal and the e-Postoffice Portal." },
  { q: "What is the price for a pack of four Gangajal bottles, including Speed Post charges?", options: ["Rs. 121.00", "Rs. 201.00", "Rs. 321.00", "Rs. 30.00"], answer: 2, explanation: "A pack of four Gangajal bottles, including Speed Post charges, costs Rs. 321.00." },
  { q: "What is the source of the Gangajal provided by India Post?", options: ["Yamunotri", "Haridwar", "Gangotri", "Prayagraj"], answer: 2, explanation: "The Gangajal provided by India Post is sourced from Gangotri." },
  { q: "Is Goods and Services Tax (GST) charged on the purchase of Gangajal from India Post?", options: ["Yes, GST is charged", "GST is charged only on bulk orders", "No GST is charged on Gangajal", "GST is included in the price"], answer: 2, explanation: "No GST is charged on the purchase of Gangajal from India Post." },
  { q: "What is the official YouTube handle for the Department of Posts?", options: ["@indiapost", "@PostOffice.in", "IndiaPost_Dop", "@IndiaPostOffice"], answer: 2, explanation: "The official YouTube handle for the Department of Posts is IndiaPost_Dop." },
  { q: "Which social media platform of the Department of Posts was inaugurated on 2nd August 2016?", options: ["Facebook page", "Twitter Seva", "Koo handle", "YouTube channel"], answer: 1, explanation: "'Twitter Seva' of the Department of Posts was inaugurated on 2nd August 2016." },
  { q: "What is the average first response time for complaints on social media for the Department of Posts?", options: ["24 hours", "4 hours", "1 hour", "48 hours"], answer: 1, explanation: "The average first response time for complaints on social media for the Department of Posts is 4 hours." },
  { q: "What is the discount percentage for a business with a monthly revenue between INR 5,00,001 and INR 25,00,000?", options: ["10%", "15%", "20%", "25%"], answer: 1, explanation: "A business with monthly revenue between INR 5,00,001 and INR 25,00,000 gets a 15% discount." },
  { q: "What is the additional discount for a contractual customer if their monthly revenue is more than 25 lakh and they pay in advance?", options: ["1%", "2%", "The discount is reduced by half", "5%"], answer: 1, explanation: "A contractual customer with monthly revenue of more than 25 lakh paying in advance gets an additional 2% discount." },
  { q: "What is the standard delivery time for a Speed Post article between two different metro cities?", options: ["1-2 Days", "1-3 Days", "1-4 Days", "4-5 Days"], answer: 1, explanation: "The standard delivery time for a Speed Post article between two different metro cities is 1-3 days." },
  { q: "What is the average delivery time for a local Speed Post article?", options: ["1-2 Days", "1-3 Days", "1-4 Days", "Same day"], answer: 0, explanation: "The average delivery time for a local Speed Post article is 1-2 days." },
  { q: "What is the price of a single 250 ml bottle of Gangajal when purchased directly at a Post Office counter?", options: ["Rs. 121.00", "Rs. 30.00", "Rs. 201.00", "It is not sold individually"], answer: 1, explanation: "A single 250 ml bottle of Gangajal costs Rs. 30.00 when purchased directly at a Post Office counter." },
  { q: "What is the official website for RAKNPA (Rafi Ahmed Kidwai National Postal Academy)?", options: ["cept.gov.in", "ecom.indiapost.gov.in", "raknpa.gov.in", "postagestamp.gov.in"], answer: 2, explanation: "The official website for RAKNPA is raknpa.gov.in." },
  { q: "What is the highest discount percentage offered to contractual customers based on monthly revenue?", options: ["20%", "25%", "30%", "15%"], answer: 2, explanation: "The highest discount percentage offered to contractual customers, for monthly revenue above INR 5,00,00,000, is 30%." },
  { q: "What is the service standard for Speed Post delivery time between a State Capital and another State Capital?", options: ["1-2 Days", "1-3 Days", "4-5 Days", "1-4 Days"], answer: 3, explanation: "The service standard for Speed Post delivery between two State Capitals is 1-4 days." },
  { q: "What is the standard service period for the 'Issue of acceptance letter' under PLI/RPLI?", options: ["5 Days", "10 Days", "15 Days", "30 Days"], answer: 2, explanation: "The standard service period for the 'Issue of acceptance letter' is 15 days." },
  { q: "How long does it take for the settlement of a maturity claim according to the PLI/RPLI service charter?", options: ["10 Days", "15 Days", "30 Days", "90 Days"], answer: 1, explanation: "Settlement of a maturity claim under the PLI/RPLI service charter takes 15 days." },
  { q: "What is the service standard for the 'Settlement of PLI/RPLI death claims' with nomination?", options: ["15 Days", "30 Days", "90 Days", "10 Days"], answer: 1, explanation: "The service standard for settlement of PLI/RPLI death claims with nomination is 30 days." },
  { q: "The longest service standard mentioned in the PLI/RPLI service charter is for which of the following tasks?", options: ["Revival of policy", "Settlement of death claims involving investigation", "Loan against policies", "Conversion of policy"], answer: 1, explanation: "Settlement of death claims involving investigation has the longest service standard at 90 days." },
  { q: "What is the time taken to settle a loan against a PLI/RPLI policy?", options: ["5 Days", "10 Days", "15 Days", "30 Days"], answer: 1, explanation: "A loan against a PLI/RPLI policy is settled within 10 days." },
  { q: "What is the service standard for a 'Change of address' under PLI/RPLI?", options: ["5 Days", "10 Days", "15 Days", "30 Days"], answer: 0, explanation: "The service standard for a 'Change of address' under PLI/RPLI is 5 days." },
  { q: "How much time is allocated for the 'Issue of duplicate policy bond' under PLI/RPLI?", options: ["5 Days", "10 Days", "15 Days", "30 Days"], answer: 1, explanation: "10 days are allocated for the 'Issue of duplicate policy bond' under PLI/RPLI." },
  { q: "What is the service standard for 'Revival of policy' under PLI/RPLI?", options: ["10 Days", "15 Days", "30 Days", "90 Days"], answer: 1, explanation: "The service standard for 'Revival of policy' under PLI/RPLI is 15 days." },
  { q: "How many days are allotted for the 'Conversion of policy' under PLI/RPLI?", options: ["5 Days", "10 Days", "15 Days", "30 Days"], answer: 1, explanation: "10 days are allotted for the 'Conversion of policy' under PLI/RPLI." },
  { q: "What is the service standard for a 'Change of nomination' under PLI/RPLI?", options: ["5 Days", "10 Days", "15 Days", "30 Days"], answer: 1, explanation: "The service standard for a 'Change of nomination' under PLI/RPLI is 10 days." },
  { q: "What is the service standard for the 'Assignment of policy' under PLI/RPLI?", options: ["5 Days", "10 Days", "15 Days", "30 Days"], answer: 1, explanation: "The service standard for 'Assignment of policy' under PLI/RPLI is 10 days." },
  { q: "What is the standard time for the 'Issue of policy bond' under PLI/RPLI?", options: ["10 Days", "15 Days", "30 Days", "90 Days"], answer: 1, explanation: "The standard time for the 'Issue of policy bond' under PLI/RPLI is 15 days." },
  { q: "What is the standard for the settlement of 'Paid up value of policy' under PLI/RPLI?", options: ["15 Days", "30 Days", "90 Days", "10 Days"], answer: 0, explanation: "The settlement of 'Paid up value of policy' under PLI/RPLI has a standard of 15 days." },
  { q: "A death claim that involves an investigation under PLI/RPLI is settled in how many days?", options: ["30 Days", "15 Days", "90 Days", "10 Days"], answer: 2, explanation: "A death claim involving an investigation under PLI/RPLI is settled within 90 days." },
  { q: "Which task has the shortest service standard under the PLI/RPLI service charter?", options: ["Change of address", "Loan against policies", "Change of nomination", "Revival of policy"], answer: 0, explanation: "'Change of address' has the shortest service standard, at 5 days, under the PLI/RPLI service charter." }
